 1→import React, { useState } from 'react';
 2→import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Search, Loader2, Shield, BookOpen, Lock, Zap } from 'lucide-react';
